const s=document.getElementById("main-nav"),e=document.getElementById("hamburger"),t=document.getElementById("nav-links");window.addEventListener("scroll",()=>{s.classList.toggle("nav--scrolled",window.scrollY>60)},{passive:!0});e.addEventListener("click",()=>{const n=t.classList.toggle("nav-links-row--open");e.setAttribute("aria-expanded",String(n)),e.classList.toggle("hamburger--open",n)});t.querySelectorAll("a").forEach(n=>{n.addEventListener("click",()=>{t.classList.remove("nav-links-row--open"),e.setAttribute("aria-expanded","false"),e.classList.remove("hamburger--open")})});document.getElementById("modern-mode-btn").addEventListener("click",()=>{window.dispatchEvent(new CustomEvent("zoomer:open"))});
